code = """import pandas as pd
import json
import re

data_file = locals()['var_function-call-15128778949534633800']
with open(data_file, 'r') as f:
    data = json.load(f)

df = pd.DataFrame(data)

def extract_state(desc):
    match = re.search(r', ([A-Z]{2}),', desc)
    if match: return match.group(1)
    match = re.search(r', ([A-Z]{2}) location', desc)
    if match: return match.group(1)
    return None

df['state'] = df['description'].apply(extract_state)
df['review_count'] = df['review_count'].astype(int)

# Sum review counts by state
state_stats = df.groupby('state')['review_count'].sum().sort_values(ascending=False)
top_state = state_stats.index[0]
total_reviews = state_stats.iloc[0]

# Get business refs
top_state_bids = df[df['state'] == top_state]['business_id'].tolist()
business_refs = [bid.replace('businessid_', 'businessref_') for bid in top_state_bids]

print("__RESULT__:")
print(json.dumps({
    "top_state": top_state,
    "total_reviews": int(total_reviews),
    "num_businesses": len(business_refs),
    "business_refs": business_refs
}))"""

